// Initialize the adversarial loop state
const config = {
  serverUrl: 'http://localhost:9100',
  totalRounds: 5,
  handsPerRound: 10,
  bots: 3,
  currentRound: 0,
  results: []
};

return [{ json: config }];

// Analyze round results and decide next steps
const config = $('Init Config').item.json;
const roundResult = $input.item.json;

const report = roundResult.report || roundResult;
const summary = report.summary || {};

config.results.push({
  round: config.currentRound + 1,
  evasionLevel: Math.min(config.currentRound, 4),
  detected: summary.detected || 0,
  warned: summary.warned || 0,
  evaded: summary.evaded || 0,
  avgScore: summary.avgScore || 0
});

config.currentRound++;

// Should we continue?
const continueLoop = config.currentRound < config.totalRounds;

return [{ json: { ...config, continueLoop, latestReport: report } }];

// Optionally adjust detector thresholds based on results
// This is where the "blue team" adapts
const config = $('Analyze Results').item.json;
const latest = config.latestReport;
const summary = latest.summary || {};

// If bots are evading (low detection rate), tighten thresholds
let newThresholds = {};
if (summary.evaded > 0) {
  // Lower the flag threshold to catch more
  newThresholds.FLAG_SCORE = Math.max(0.35, 0.55 - (config.currentRound * 0.03));
  newThresholds.WARN_SCORE = Math.max(0.25, 0.40 - (config.currentRound * 0.02));
}

return [{ json: { config, newThresholds, hasUpdates: Object.keys(newThresholds).length > 0 } }];

// Build final scorecard
const config = $('Analyze Results').item.json;

const scorecard = {
  totalRounds: config.results.length,
  rounds: config.results,
  detectorImprovement: {
    firstRoundAvgScore: config.results[0]?.avgScore || 0,
    lastRoundAvgScore: config.results[config.results.length - 1]?.avgScore || 0
  },
  botEvasionSuccess: config.results.map(r => ({
    level: r.evasionLevel,
    evadeRate: r.evaded / (r.detected + r.warned + r.evaded || 1)
  }))
};

return [{ json: scorecard }];
